import SwiftUI

struct CountRateFormatted {

    let value: Float?
    let unit: LocalizedStringResource

    init(rawValue: Float?, unit: Settings.CountRateMeasurementUnit) {
        if unit == .cpm {
            self.value = rawValue.map { $0 * 60 }
            self.unit = "cpm"
        } else {
            self.value = rawValue
            self.unit = .Localization.cps
        }
    }
}
